import okhttp3.OkHttpClient
import okhttp3.Request
import java.net.URL

class IoTDeviceClient(private val baseUrl: String) {
    private val client = OkHttpClient()

    fun getDataFromIoTDevice(deviceId: String): String? {
        return try {
            val request = Request.Builder().url("$baseUrl/$deviceId").build()
            val response = client.newCall(request).execute()
            if (response.isSuccessful) {
                response.body?.string()
            } else {
                null
            }
        } catch (e: IOException) {
            e.printStackTrace()
            null
        }
    }

    fun postDataToIoTDevice(deviceId: String, data: String): Boolean {
        return try {
            val request = Request.Builder().url("$baseUrl/$deviceId").post(data.toRequestBody()).build()
            val response = client.newCall(request).execute()
            if (response.isSuccessful) {
                true
            } else {
                false
            }
        } catch (e: IOException) {
            e.printStackTrace()
            false
        }
    }
}